# ---------------------------------------------------------------------------
# Sub-objects that expose the shared lock
# ---------------------------------------------------------------------------
class _Store:
    """Thin object holding the shared lock reference."""

    def __init__(self, lock):
        self._lock = lock


class _Service:
    """Thin object holding the shared lock reference."""

    def __init__(self, lock):
        self._lock = lock


# ---------------------------------------------------------------------------
# PDF builder (verbatim from spec)
# ---------------------------------------------------------------------------
def _build_pdf_bytes(lines):
    def esc(s):
        return s.replace("\\", "\\\\").replace("(", "\\(").replace(")", "\\)")

    parts = ["BT", "/F1 12 Tf", "14 TL", "50 760 Td"]
    if not lines:
        lines = [""]
    for ln in lines:
        parts.append("({0}) Tj T*".format(esc(str(ln))))
    parts.append("ET")
    stream_bytes = "\n".join(parts).encode("latin-1", "replace")
    objects = [
        b"<< /Type /Catalog /Pages 2 0 R >>",
        b"<< /Type /Pages /Kids [3 0 R] /Count 1 >>",
        b"<< /Type /Page /Parent 2 0 R /MediaBox [0 0 612 792] "
        b"/Resources << /Font << /F1 5 0 R >> >> /Contents 4 0 R >>",
        b"<< /Length " + str(len(stream_bytes)).encode("ascii") +
        b" >>\nstream\n" + stream_bytes + b"\nendstream",
        b"<< /Type /Font /Subtype /Type1 /BaseFont /Helvetica >>",
    ]
    out = bytearray(b"%PDF-1.4\n")
    offsets = []
    for i, obj in enumerate(objects, start=1):
        offsets.append(len(out))
        out += str(i).encode("ascii") + b" 0 obj\n" + obj + b"\nendobj\n"
    xref_pos = len(out)
    n = len(objects) + 1
    out += b"xref\n0 " + str(n).encode("ascii") + b"\n"
    out += b"0000000000 65535 f \n"
    for off in offsets:
        out += ("{0:010d} 00000 n \n".format(off)).encode("ascii")
    out += b"trailer\n<< /Size " + str(n).encode("ascii") + b" /Root 1 0 R >>\n"
    out += b"startxref\n" + str(xref_pos).encode("ascii") + b"\n%%EOF\n"
    return bytes(out)


# ---------------------------------------------------------------------------
# Main manager
# ---------------------------------------------------------------------------
class TeamCollaborationManager:

    def __init__(self, now=None):
        self._now = now if now is not None else datetime.now
        self._lock = threading.RLock()
        self._id_counter = 0

        # Sub-objects — each holds a reference to the SAME lock
        self.users = _Store(self._lock)
        self.projects = _Store(self._lock)
        self.tasks = _Store(self._lock)
        self.messages = _Store(self._lock)
        self.performance = _Service(self._lock)
        self.reports = _Service(self._lock)

        # Primary storage
        self._users = {}        # id -> User
        self._projects = {}     # id -> Project
        self._tasks = {}        # id -> Task
        self._messages = {}     # id -> Message
        self._ratings = []      # list[Rating]

        # Indices
        self._assignee_index = {}    # user_id -> set[task_id]
        self._project_tasks = {}     # project_id -> list[task_id]
        self._project_messages = {}  # project_id -> list[message_id]
        self._task_messages = {}     # task_id -> list[message_id]

    def _next_id(self):
        self._id_counter += 1
        return self._id_counter

    # -----------------------------------------------------------------------
    # User management
    # -----------------------------------------------------------------------

    def register_user(self, username, email, role=UserRole.MEMBER):
        with self._lock:
            if not username or not username.strip():
                raise ValidationError("username must be non-empty")
            if not email or "@" not in email:
                raise ValidationError("email must be non-empty and contain @")
            if not isinstance(role, UserRole):
                raise ValidationError("role must be a UserRole instance")
            for u in self._users.values():
                if u.username == username:
                    raise DuplicateError("username already exists")
            for u in self._users.values():
                if u.email == email:
                    raise DuplicateError("email already exists")
            user = User(
                id=self._next_id(),
                username=username,
                email=email,
                role=role,
                created_at=self._now(),
            )
            self._users[user.id] = user
            return copy.deepcopy(user)

    def get_user(self, user_id):
        with self._lock:
            if user_id not in self._users:
                raise NotFoundError("user not found")
            return copy.deepcopy(self._users[user_id])

    def list_users(self):
        with self._lock:
            return [
                copy.deepcopy(u)
                for u in sorted(self._users.values(), key=lambda u: u.id)
            ]

    def update_user(self, user_id, username=None, email=None, role=None):
        with self._lock:
            if user_id not in self._users:
                raise NotFoundError("user not found")
            user = self._users[user_id]

            if email is not None and "@" not in email:
                raise ValidationError("email must contain @")
            if role is not None and not isinstance(role, UserRole):
                raise ValidationError("role must be a UserRole instance")

            if username is not None and username != user.username:
                for u in self._users.values():
                    if u.id != user_id and u.username == username:
                        raise DuplicateError("username already exists")

            if email is not None and email != user.email:
                for u in self._users.values():
                    if u.id != user_id and u.email == email:
                        raise DuplicateError("email already exists")

            if username is not None:
                user.username = username
            if email is not None:
                user.email = email
            if role is not None:
                user.role = role

            return copy.deepcopy(user)

    def delete_user(self, user_id):
        with self._lock:
            if user_id not in self._users:
                raise NotFoundError("user not found")
            for p in self._projects.values():
                if p.owner_id == user_id:
                    raise ConflictError("user owns projects")
            task_ids = self._assignee_index.get(user_id, set())
            for tid in task_ids:
                task = self._tasks.get(tid)
                if task and task.status != TaskStatus.COMPLETED:
                    raise ConflictError("user has open tasks")
            del self._users[user_id]
            self._assignee_index.pop(user_id, None)

    # -----------------------------------------------------------------------
    # Project management
    # -----------------------------------------------------------------------

    def create_project(self, name, start_date, end_date, owner_id, description=""):
        with self._lock:
            if not name or not name.strip():
                raise ValidationError("name must be non-empty")
            if end_date < start_date:
                raise ValidationError("end_date must be >= start_date")
            if owner_id not in self._users:
                raise NotFoundError("owner not found")
            project = Project(
                id=self._next_id(),
                name=name,
                description=description,
                start_date=start_date,
                end_date=end_date,
                owner_id=owner_id,
                created_at=self._now(),
            )
            self._projects[project.id] = project
            self._project_tasks[project.id] = []
            self._project_messages[project.id] = []
            return copy.deepcopy(project)

    def get_project(self, project_id):
        with self._lock:
            if project_id not in self._projects:
                raise NotFoundError("project not found")
            return copy.deepcopy(self._projects[project_id])

    def list_projects(self):
        with self._lock:
            return [
                copy.deepcopy(p)
                for p in sorted(self._projects.values(), key=lambda p: p.id)
            ]

    def update_project(self, project_id, name=None, start_date=None, end_date=None, description=None):
        with self._lock:
            if project_id not in self._projects:
                raise NotFoundError("project not found")
            project = self._projects[project_id]

            new_name = name if name is not None else project.name
            new_start = start_date if start_date is not None else project.start_date
            new_end = end_date if end_date is not None else project.end_date

            if not new_name or not new_name.strip():
                raise ValidationError("name must be non-empty")
            if new_end < new_start:
                raise ValidationError("end_date must be >= start_date")

            project.name = new_name
            project.start_date = new_start
            project.end_date = new_end
            if description is not None:
                project.description = description

            return copy.deepcopy(project)

    def delete_project(self, project_id):
        with self._lock:
            if project_id not in self._projects:
                raise NotFoundError("project not found")

            # Cascade: delete all tasks for this project
            for tid in list(self._project_tasks.get(project_id, [])):
                task = self._tasks.get(tid)
                if task is not None and task.assignee_id is not None:
                    idx = self._assignee_index.get(task.assignee_id)
                    if idx is not None:
                        idx.discard(tid)
                # Delete task-level messages
                for mid in list(self._task_messages.get(tid, [])):
                    self._messages.pop(mid, None)
                self._task_messages.pop(tid, None)
                self._tasks.pop(tid, None)

            # Cascade: delete all project-level messages
            for mid in list(self._project_messages.get(project_id, [])):
                self._messages.pop(mid, None)

            self._project_tasks.pop(project_id, None)
            self._project_messages.pop(project_id, None)
            del self._projects[project_id]

    # -----------------------------------------------------------------------
    # Task management
    # -----------------------------------------------------------------------

    def create_task(self, project_id, title, assignee_id=None, deadline=None):
        with self._lock:
            if project_id not in self._projects:
                raise NotFoundError("project not found")
            project = self._projects[project_id]

            if not title or not title.strip():
                raise ValidationError("title must be non-empty")

            if assignee_id is not None and assignee_id not in self._users:
                raise NotFoundError("assignee not found")

            if deadline is not None and deadline < project.start_date:
                raise ValidationError("deadline must be >= project start_date")

            task = Task(
                id=self._next_id(),
                project_id=project_id,
                title=title,
                status=TaskStatus.NOT_STARTED,
                assignee_id=assignee_id,
                deadline=deadline,
                started_at=None,
                completed_at=None,
                created_at=self._now(),
            )
            self._tasks[task.id] = task
            self._project_tasks[project_id].append(task.id)

            if assignee_id is not None:
                if assignee_id not in self._assignee_index:
                    self._assignee_index[assignee_id] = set()
                self._assignee_index[assignee_id].add(task.id)

            return copy.deepcopy(task)

    def get_task(self, task_id):
        with self._lock:
            if task_id not in self._tasks:
                raise NotFoundError("task not found")
            return copy.deepcopy(self._tasks[task_id])

    def list_tasks_by_project(self, project_id):
        with self._lock:
            if project_id not in self._projects:
                raise NotFoundError("project not found")
            task_ids = self._project_tasks.get(project_id, [])
            tasks = [self._tasks[tid] for tid in task_ids if tid in self._tasks]
            return [copy.deepcopy(t) for t in sorted(tasks, key=lambda t: t.id)]

    def list_tasks_by_assignee(self, user_id):
        with self._lock:
            if user_id not in self._users:
                raise NotFoundError("user not found")
            task_ids = self._assignee_index.get(user_id, set())
            tasks = [self._tasks[tid] for tid in task_ids if tid in self._tasks]
            return [copy.deepcopy(t) for t in sorted(tasks, key=lambda t: t.id)]

    def assign_task(self, task_id, assignee_id):
        with self._lock:
            if task_id not in self._tasks:
                raise NotFoundError("task not found")
            if assignee_id not in self._users:
                raise NotFoundError("assignee not found")
            task = self._tasks[task_id]
            # Remove from old assignee index
            if task.assignee_id is not None:
                idx = self._assignee_index.get(task.assignee_id)
                if idx is not None:
                    idx.discard(task_id)
            # Update assignee
            task.assignee_id = assignee_id
            if assignee_id not in self._assignee_index:
                self._assignee_index[assignee_id] = set()
            self._assignee_index[assignee_id].add(task_id)
            return copy.deepcopy(task)

    def reassign_task(self, task_id, new_assignee_id):
        return self.assign_task(task_id, new_assignee_id)

    def unassign_task(self, task_id):
        with self._lock:
            if task_id not in self._tasks:
                raise NotFoundError("task not found")
            task = self._tasks[task_id]
            if task.assignee_id is not None:
                idx = self._assignee_index.get(task.assignee_id)
                if idx is not None:
                    idx.discard(task_id)
                task.assignee_id = None
            return copy.deepcopy(task)

    def set_deadline(self, task_id, deadline):
        with self._lock:
            if task_id not in self._tasks:
                raise NotFoundError("task not found")
            task = self._tasks[task_id]
            if deadline is not None:
                project = self._projects[task.project_id]
                if deadline < project.start_date:
                    raise ValidationError("deadline must be >= project start_date")
            task.deadline = deadline
            return copy.deepcopy(task)

    def update_status(self, task_id, status):
        with self._lock:
            if not isinstance(status, TaskStatus):
                raise ValidationError("status must be a TaskStatus instance")
            if task_id not in self._tasks:
                raise NotFoundError("task not found")
            task = self._tasks[task_id]
            now = self._now()

            if status == TaskStatus.IN_PROGRESS:
                if task.started_at is None:
                    task.started_at = now
                task.completed_at = None
            elif status == TaskStatus.COMPLETED:
                if task.started_at is None:
                    task.started_at = now
                task.completed_at = now
            elif status == TaskStatus.NOT_STARTED:
                task.started_at = None
                task.completed_at = None

            task.status = status
            return copy.deepcopy(task)

    # -----------------------------------------------------------------------
    # Messaging
    # -----------------------------------------------------------------------

    def post_message(self, author_id, body, project_id=None, task_id=None,
                     parent_id=None, attachments=None):
        with self._lock:
            if author_id not in self._users:
                raise NotFoundError("author not found")

            if project_id is None and task_id is None:
                raise ValidationError("must provide exactly one of project_id or task_id")
            if project_id is not None and task_id is not None:
                raise ValidationError("cannot provide both project_id and task_id")

            if project_id is not None and project_id not in self._projects:
                raise NotFoundError("project not found")
            if task_id is not None and task_id not in self._tasks:
                raise NotFoundError("task not found")

            att_list = []
            if attachments:
                for filename, data in attachments:
                    att_list.append(Attachment(
                        filename=filename,
                        size=len(data),
                        uploaded_by=author_id,
                        uploaded_at=self._now(),
                    ))

            if not body and not att_list:
                raise ValidationError("body must be non-empty if no attachments")

            if parent_id is not None and parent_id not in self._messages:
                raise NotFoundError("parent message not found")

            msg = Message(
                id=self._next_id(),
                author_id=author_id,
                body=body,
                project_id=project_id,
                task_id=task_id,
                parent_id=parent_id,
                attachments=att_list,
                created_at=self._now(),
                edited_at=None,
            )
            self._messages[msg.id] = msg

            if project_id is not None:
                self._project_messages.setdefault(project_id, []).append(msg.id)
            if task_id is not None:
                self._task_messages.setdefault(task_id, []).append(msg.id)

            return copy.deepcopy(msg)

    def edit_message(self, message_id, editor_id, new_body):
        with self._lock:
            if message_id not in self._messages:
                raise NotFoundError("message not found")
            msg = self._messages[message_id]
            if msg.author_id != editor_id:
                raise AuthorizationError("only author can edit message")
            if not new_body:
                raise ValidationError("new_body must be non-empty")
            msg.body = new_body
            msg.edited_at = self._now()
            return copy.deepcopy(msg)

    def add_attachment(self, message_id, user_id, filename, data):
        with self._lock:
            if message_id not in self._messages:
                raise NotFoundError("message not found")
            msg = self._messages[message_id]
            if msg.author_id != user_id:
                raise AuthorizationError("only author can add attachments")
            if not filename:
                raise ValidationError("filename must be non-empty")
            att = Attachment(
                filename=filename,
                size=len(data),
                uploaded_by=user_id,
                uploaded_at=self._now(),
            )
            msg.attachments.append(att)
            return copy.deepcopy(msg)

    def list_messages_by_project(self, project_id):
        with self._lock:
            if project_id not in self._projects:
                raise NotFoundError("project not found")
            msg_ids = self._project_messages.get(project_id, [])
            msgs = [self._messages[mid] for mid in msg_ids if mid in self._messages]
            return [copy.deepcopy(m) for m in sorted(msgs, key=lambda m: m.id)]

    def list_messages_by_task(self, task_id):
        with self._lock:
            if task_id not in self._tasks:
                raise NotFoundError("task not found")
            msg_ids = self._task_messages.get(task_id, [])
            msgs = [self._messages[mid] for mid in msg_ids if mid in self._messages]
            return [copy.deepcopy(m) for m in sorted(msgs, key=lambda m: m.id)]

    def delete_message(self, message_id, user_id):
        with self._lock:
            if message_id not in self._messages:
                raise NotFoundError("message not found")
            msg = self._messages[message_id]
            if msg.author_id != user_id:
                raise AuthorizationError("only author can delete message")
            # Remove from indices
            if msg.project_id is not None:
                lst = self._project_messages.get(msg.project_id)
                if lst is not None:
                    try:
                        lst.remove(message_id)
                    except ValueError:
                        pass
            if msg.task_id is not None:
                lst = self._task_messages.get(msg.task_id)
                if lst is not None:
                    try:
                        lst.remove(message_id)
                    except ValueError:
                        pass
            del self._messages[message_id]

    # -----------------------------------------------------------------------
    # Performance
    # -----------------------------------------------------------------------

    def get_completion_rate(self, user_id):
        with self._lock:
            if user_id not in self._users:
                raise NotFoundError("user not found")
            task_ids = self._assignee_index.get(user_id, set())
            tasks = [self._tasks[tid] for tid in task_ids if tid in self._tasks]
            if not tasks:
                return 0.0
            completed = sum(1 for t in tasks if t.status == TaskStatus.COMPLETED)
            return completed / len(tasks)

    def get_average_completion_time(self, user_id):
        with self._lock:
            if user_id not in self._users:
                raise NotFoundError("user not found")
            task_ids = self._assignee_index.get(user_id, set())
            tasks = [self._tasks[tid] for tid in task_ids if tid in self._tasks]
            completed = [
                t for t in tasks
                if t.status == TaskStatus.COMPLETED
                and t.started_at is not None
                and t.completed_at is not None
            ]
            if not completed:
                return None
            total = sum(
                (t.completed_at - t.started_at).total_seconds() for t in completed
            )
            return total / len(completed)

    def submit_rating(self, rater_id, ratee_id, score, feedback="", task_id=None):
        with self._lock:
            if rater_id == ratee_id:
                raise ConflictError("cannot rate yourself")
            if not isinstance(score, int) or isinstance(score, bool) or score < 1 or score > 5:
                raise ValidationError("score must be int in 1..5")
            if rater_id not in self._users:
                raise NotFoundError("rater not found")
            if ratee_id not in self._users:
                raise NotFoundError("ratee not found")
            if task_id is not None and task_id not in self._tasks:
                raise NotFoundError("task not found")
            rating = Rating(
                id=self._next_id(),
                rater_id=rater_id,
                ratee_id=ratee_id,
                score=score,
                feedback=feedback,
                task_id=task_id,
                created_at=self._now(),
            )
            self._ratings.append(rating)
            return copy.deepcopy(rating)

    def get_ratings_summary(self, user_id):
        with self._lock:
            if user_id not in self._users:
                raise NotFoundError("user not found")
            ratings = [r for r in self._ratings if r.ratee_id == user_id]
            count = len(ratings)
            average = sum(r.score for r in ratings) / count if count > 0 else 0.0
            return {
                "count": count,
                "average": average,
                "ratings": [copy.deepcopy(r) for r in ratings],
            }

    def get_user_dashboard(self, user_id):
        with self._lock:
            if user_id not in self._users:
                raise NotFoundError("user not found")
            task_ids = self._assignee_index.get(user_id, set())
            tasks = [self._tasks[tid] for tid in task_ids if tid in self._tasks]
            total = len(tasks)
            completed = sum(1 for t in tasks if t.status == TaskStatus.COMPLETED)
            in_progress = sum(1 for t in tasks if t.status == TaskStatus.IN_PROGRESS)
            not_started = sum(1 for t in tasks if t.status == TaskStatus.NOT_STARTED)
            completion_rate = completed / total if total > 0 else 0.0

            finished = [
                t for t in tasks
                if t.status == TaskStatus.COMPLETED
                and t.started_at is not None
                and t.completed_at is not None
            ]
            avg_time = (
                sum((t.completed_at - t.started_at).total_seconds() for t in finished)
                / len(finished)
            ) if finished else None

            ratings = [r for r in self._ratings if r.ratee_id == user_id]
            rating_count = len(ratings)
            rating_average = (
                sum(r.score for r in ratings) / rating_count if rating_count > 0 else 0.0
            )

            return {
                "total_tasks": total,
                "completed_tasks": completed,
                "in_progress_tasks": in_progress,
                "not_started_tasks": not_started,
                "completion_rate": completion_rate,
                "average_completion_time": avg_time,
                "rating_count": rating_count,
                "rating_average": rating_average,
            }

    # -----------------------------------------------------------------------
    # Reports
    # -----------------------------------------------------------------------

    def project_progress_report(self, project_id):
        with self._lock:
            if project_id not in self._projects:
                raise NotFoundError("project not found")

            task_ids = self._project_tasks.get(project_id, [])
            tasks = [self._tasks[tid] for tid in task_ids if tid in self._tasks]
            total = len(tasks)

            status_counts = {
                TaskStatus.NOT_STARTED.value: 0,
                TaskStatus.IN_PROGRESS.value: 0,
                TaskStatus.COMPLETED.value: 0,
            }
            for t in tasks:
                status_counts[t.status.value] += 1

            completed_count = status_counts[TaskStatus.COMPLETED.value]
            completion_rate = completed_count / total if total > 0 else 0.0

            now = self._now()
            overdue = sum(
                1 for t in tasks
                if t.deadline is not None
                and t.deadline < now
                and t.status != TaskStatus.COMPLETED
            )

            per_assignee = {}
            for t in tasks:
                if t.assignee_id is not None:
                    uid = t.assignee_id
                    if uid not in per_assignee:
                        per_assignee[uid] = {
                            "total": 0,
                            "completed": 0,
                            "in_progress": 0,
                            "not_started": 0,
                        }
                    per_assignee[uid]["total"] += 1
                    if t.status == TaskStatus.COMPLETED:
                        per_assignee[uid]["completed"] += 1
                    elif t.status == TaskStatus.IN_PROGRESS:
                        per_assignee[uid]["in_progress"] += 1
                    else:
                        per_assignee[uid]["not_started"] += 1

            return {
                "report_type": ReportType.PROJECT_PROGRESS.value,
                "project_id": project_id,
                "total_tasks": total,
                "status_counts": status_counts,
                "completion_rate": completion_rate,
                "overdue_tasks": overdue,
                "per_assignee": per_assignee,
            }

    def team_performance_report(self, project_id=None):
        with self._lock:
            if project_id is not None and project_id not in self._projects:
                raise NotFoundError("project not found")

            columns = [
                "user_id", "username", "total_tasks", "completed_tasks",
                "completion_rate", "average_completion_time",
                "rating_average", "rating_count",
            ]

            if project_id is None:
                user_ids = list(self._users.keys())
            else:
                task_ids = self._project_tasks.get(project_id, [])
                tasks = [self._tasks[tid] for tid in task_ids if tid in self._tasks]
                user_ids = list({t.assignee_id for t in tasks if t.assignee_id is not None})

            rows = []
            for uid in user_ids:
                user = self._users[uid]
                uid_task_ids = self._assignee_index.get(uid, set())
                user_tasks = [self._tasks[tid] for tid in uid_task_ids if tid in self._tasks]
                total = len(user_tasks)
                completed = sum(1 for t in user_tasks if t.status == TaskStatus.COMPLETED)
                comp_rate = completed / total if total > 0 else 0.0
                finished = [
                    t for t in user_tasks
                    if t.status == TaskStatus.COMPLETED
                    and t.started_at is not None
                    and t.completed_at is not None
                ]
                avg_time = (
                    sum((t.completed_at - t.started_at).total_seconds() for t in finished)
                    / len(finished)
                ) if finished else None
                ratings = [r for r in self._ratings if r.ratee_id == uid]
                rc = len(ratings)
                ra = sum(r.score for r in ratings) / rc if rc > 0 else 0.0
                rows.append({
                    "user_id": uid,
                    "username": user.username,
                    "total_tasks": total,
                    "completed_tasks": completed,
                    "completion_rate": comp_rate,
                    "average_completion_time": avg_time,
                    "rating_average": ra,
                    "rating_count": rc,
                })

            return {
                "report_type": ReportType.TEAM_PERFORMANCE.value,
                "columns": columns,
                "rows": rows,
            }

    def individual_performance_report(self, user_id):
        with self._lock:
            if user_id not in self._users:
                raise NotFoundError("user not found")
            user = self._users[user_id]
            task_ids = self._assignee_index.get(user_id, set())
            tasks = [self._tasks[tid] for tid in task_ids if tid in self._tasks]
            total = len(tasks)
            completed = sum(1 for t in tasks if t.status == TaskStatus.COMPLETED)
            in_progress = sum(1 for t in tasks if t.status == TaskStatus.IN_PROGRESS)
            not_started = sum(1 for t in tasks if t.status == TaskStatus.NOT_STARTED)
            completion_rate = completed / total if total > 0 else 0.0
            finished = [
                t for t in tasks
                if t.status == TaskStatus.COMPLETED
                and t.started_at is not None
                and t.completed_at is not None
            ]
            avg_time = (
                sum((t.completed_at - t.started_at).total_seconds() for t in finished)
                / len(finished)
            ) if finished else None
            ratings = [r for r in self._ratings if r.ratee_id == user_id]
            rc = len(ratings)
            ra = sum(r.score for r in ratings) / rc if rc > 0 else 0.0
            task_list = [
                {
                    "task_id": t.id,
                    "title": t.title,
                    "status": t.status.value,
                    "project_id": t.project_id,
                    "deadline": t.deadline,
                    "started_at": t.started_at,
                    "completed_at": t.completed_at,
                    "created_at": t.created_at,
                }
                for t in sorted(tasks, key=lambda t: t.id)
            ]
            return {
                "report_type": ReportType.INDIVIDUAL_PERFORMANCE.value,
                "user_id": user_id,
                "username": user.username,
                "total_tasks": total,
                "completed_tasks": completed,
                "in_progress_tasks": in_progress,
                "not_started_tasks": not_started,
                "completion_rate": completion_rate,
                "average_completion_time": avg_time,
                "rating_average": ra,
                "rating_count": rc,
                "tasks": task_list,
            }

    def export_report(self, report, fmt):
        with self._lock:
            if not isinstance(report, dict):
                raise ValidationError("report must be a dict")
            if not isinstance(fmt, ReportFormat):
                raise ValidationError("fmt must be a ReportFormat instance")

            if fmt == ReportFormat.CSV:
                output = io.StringIO()
                writer = csv.writer(output)

                if "rows" in report:
                    columns = report.get("columns")
                    if not columns:
                        columns = list(report["rows"][0].keys()) if report["rows"] else []
                    writer.writerow(columns)
                    for row in report["rows"]:
                        writer.writerow([row.get(col, "") for col in columns])
                else:
                    writer.writerow(["field", "value"])
                    for key, value in report.items():
                        writer.writerow([key, str(value)])

                return output.getvalue()

            else:  # ReportFormat.PDF
                lines = ["{0}: {1}".format(k, v) for k, v in report.items()]
                return _build_pdf_bytes(lines)
